-- =====================================================================
-- step 07 — t_prd_product_option_items (INSERTABLE · 차원행 포인터)
-- 트리거 fn_chk_opt_item_ref: ref_dim_cd별 (prd_cd+키) 차원행 EXISTS 행단위 검사.
--   .06 도수=opt_id::int / .03 자재=mat_cd+usage_cd / .04 공정=proc_cd.
-- 멱등 가드 = (prd_cd, opt_cd, item_seq) NOT EXISTS. opt_cd=(prd,grp,opt_nm) resolve.
-- ref_key1 NOT NULL. BLOCKED(접지/화이트별색)은 _blocked/07_*.sql(적재 대상 아님).
-- reg_dt 생략→DEFAULT now(). 손편집 금지.
-- =====================================================================
INSERT INTO t_prd_product_option_items (prd_cd, opt_cd, item_seq, ref_dim_cd, ref_key1, ref_key2, qty, use_yn)
SELECT 'PRD_000016', (SELECT opt_cd FROM t_prd_product_options o WHERE o.prd_cd='PRD_000016' AND o.opt_nm='단면' AND o.opt_grp_cd=(SELECT opt_grp_cd FROM t_prd_product_option_groups WHERE prd_cd='PRD_000016' AND opt_grp_nm='인쇄' AND del_yn='N' LIMIT 1) AND o.del_yn='N' ORDER BY o.opt_cd LIMIT 1), 1, 'OPT_REF_DIM.06', '1', NULL, 1, 'Y'
WHERE NOT EXISTS (SELECT 1 FROM t_prd_product_option_items
  WHERE prd_cd = 'PRD_000016' AND opt_cd = (SELECT opt_cd FROM t_prd_product_options o WHERE o.prd_cd='PRD_000016' AND o.opt_nm='단면' AND o.opt_grp_cd=(SELECT opt_grp_cd FROM t_prd_product_option_groups WHERE prd_cd='PRD_000016' AND opt_grp_nm='인쇄' AND del_yn='N' LIMIT 1) AND o.del_yn='N' ORDER BY o.opt_cd LIMIT 1) AND item_seq = 1);
